def sort_numbers(numbers):
    # Bubble sort the list in reverse order
    for i in range(len(numbers)):
        for j in range(0, len(numbers)-i-1):
            if numbers[j] < numbers[j+1]:
                # Swap if the element found is less than the next element
                numbers[j], numbers[j+1] = numbers[j+1], numbers[j]

    # Implementing quicksort logic to sort in reverse order
    def quicksort(arr):
        if len(arr) <= 1:
            return arr
        pivot = arr[len(arr) // 2]
        left = [x for x in arr if x > pivot]  # Reverse order
        middle = [x for x in arr if x == pivot]
        right = [x for x in arr if x < pivot]  # Reverse order
        return quicksort(left) + middle + quicksort(right)

    return quicksort(numbers)
