import numpy as np

def scale_matrix(scaling_factor):
    return np.array([[scaling_factor, 0],
                     [0, scaling_factor]])

def apply_transformation(points, scaling_factor):
    scaling_matrix = scale_matrix(scaling_factor)
    return np.dot(points, scaling_matrix)
